CREATE TABLE final_price_table_1290828_qq_com(
  "物料号码" TEXT,
  "物料长描述" TEXT,
  "匹配名称" TEXT,
  DN1,
  DN2,
  "壁厚",
  "其他壁厚",
  "数字壁厚",
  "材质" TEXT,
  "材质系数" REAL,
  "弯曲半径系数",
  "角度系数",
  "特殊管件系数",
  "镀锌",
  "低温",
  "脱脂",
  "抗硫氢系数",
  "抛光"
, 其他壁厚单价 REAL, 匹配框架表壁厚 REAL, 数字壁厚单价 REAL, 换算后价格 REAL, 最终核价 REAL);
CREATE TABLE IF NOT EXISTS "product_attributes" (
    "序号" INTEGER PRIMARY KEY AUTOINCREMENT,
    "名称" TEXT NOT NULL,
    "DN1" REAL NOT NULL,
    "DN2" REAL,
    "壁厚" REAL,
    "材质" TEXT NOT NULL,
    "其他壁厚" TEXT
);
CREATE TABLE IF NOT EXISTS "product_prices" (
    "序号" INTEGER NOT NULL,
    "厂商" TEXT NOT NULL,
    "单价" REAL NOT NULL, "包段" TEXT,
    PRIMARY KEY ("序号", "厂商"),
    FOREIGN KEY ("序号") REFERENCES "product_attributes"("序号") ON DELETE CASCADE
);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX idx_test_R_radius ON "tbl_R"("弯曲半径");
CREATE INDEX idx_attr_composite ON product_attributes("名称", "DN1", "材质");
CREATE INDEX idx_attr_dn2 ON product_attributes("DN2");
CREATE INDEX idx_attr_thickness ON product_attributes("壁厚");
CREATE INDEX idx_attr_other_thick ON product_attributes("其他壁厚");
CREATE INDEX idx_price_vendor ON product_prices("厂商");
